request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?modelId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId ?modelId .
  FILTER(?modelId = "5ee15f85aeb74d8d9e31df0e41fea6fe")

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?gw a bboExt:ExclusiveGateway ;
      tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?gw ?gwName ?modelId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:normalizedId ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(
    (?modelId = "5ee15f85aeb74d8d9e31df0e41fea6fe") ||
    (?origId = "5ee15f85aeb74d8d9e31df0e41fea6fe")
  )

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?gw a bboExt:ExclusiveGateway ;
      tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
}
LIMIT 25
